using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xYConstructionPlane());
    if (!sketch)
        return false;

    // Create two sketch circles
    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;

    Ptr circles = curves->sketchCircles();
    if (!circles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    circles->addByCenterRadius(centerPoint, 5.0);
    Ptr centerPointTwo = Point3D::create(10.0, 0, 0);
    circles->addByCenterRadius(centerPointTwo, 5.0);

    // Get the profiles defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;

    Ptr prof = profs->item(0);
    Ptr profTwo = profs->item(1);

    // Get area properties from a profile
    Ptr areaProps = prof->areaProperties(CalculationAccuracy::LowCalculationAccuracy);
    if (!areaProps)
        return false;

    // Get area
    double area = areaProps->area();

    // Get centroid
    Ptr centroid = areaProps->centroid();

    // Get perimeter
    double perimeter = areaProps->perimeter();

    // Get angle of rotation of the principal axes
    double rotationOfPrincipal = areaProps->rotationToPrincipal();

    // Accuracy
    CalculationAccuracy accuracy = areaProps->accuracy();

    // Get area properties from two profiles
    Ptr inputs = ObjectCollection::create();
    if (!inputs)
        return false;
    inputs->add(prof);
    inputs->add(profTwo);
    areaProps = design->areaProperties(inputs);
    if (!areaProps)
        return false;

    // Get principal axes
    Ptr xAxis;
    Ptr yAxis;
    areaProps->getPrincipalAxes(xAxis, yAxis);

    // Get moments of inertia
    double ixx = 0, iyy = 0, izz = 0, ixy = 0, iyz = 0, ixz = 0;
    areaProps->getMomentsOfInertia(ixx, iyy, izz, ixy, iyz, ixz);

    // Get centroid moments of inertia
    double centixx = 0, centiyy = 0, centizz = 0, centixy = 0, centiyz = 0, centixz = 0;
    areaProps->getCentroidMomentsOfInertia(centixx, centiyy, centizz, centixy, centiyz, centixz);

    // Get principal moments of inertia
    double i1 = 0, i2 = 0, i3 = 0;
    areaProps->getPrincipalMomentsOfInertia(i1, i2, i3);

    // Get radius of gyration
    double kxx = 0, kyy = 0, kzz = 0;
    areaProps->getRadiusOfGyration(kxx, kyy, kzz);

    return true;
}
